const projects = [
  { id: 'PROY-01', name: 'Portal de aliados', owner: 'Lucía', status: 'en_riesgo', priority: 'alta', due: '2026-07-24', progress: 62, blocker: 'Falta decisión de Legal sobre términos.' },
  { id: 'PROY-02', name: 'Onboarding comercial', owner: 'Miguel', status: 'en_curso', priority: 'media', due: '2026-08-02', progress: 48, blocker: '' },
  { id: 'PROY-03', name: 'Migración CRM', owner: 'Sara', status: 'bloqueado', priority: 'critica', due: '2026-07-22', progress: 31, blocker: 'Proveedor no entregó acceso a la API.' }
];
const events = [
  { id: 'EVT-01', title: 'Comité de lanzamiento', start: '2026-07-21T09:00:00-05:00', projectId: 'PROY-01', type: 'decision' },
  { id: 'EVT-02', title: 'Demo de onboarding', start: '2026-07-23T15:00:00-05:00', projectId: 'PROY-02', type: 'milestone' },
  { id: 'EVT-03', title: 'Escalamiento con proveedor', start: '2026-07-20T16:30:00-05:00', projectId: 'PROY-03', type: 'blocker' }
];
const milestones = [
  { id: 'HIT-01', projectId: 'PROY-01', title: 'Aprobación de términos', date: '2026-07-21', status: 'at_risk' },
  { id: 'HIT-02', projectId: 'PROY-02', title: 'Piloto con ventas', date: '2026-07-26', status: 'on_track' },
  { id: 'HIT-03', projectId: 'PROY-03', title: 'Acceso a API CRM', date: '2026-07-20', status: 'blocked' }
];
return [{ json: { capturedAt, projects, events, milestones } }];

const data = $input.first().json;
const byProject = new Map(data.projects.map((project) => [project.id, { ...project, events: [], milestones: [] }]));
for (const event of data.events) byProject.get(event.projectId)?.events.push(event);
for (const milestone of data.milestones) byProject.get(milestone.projectId)?.milestones.push(milestone);
const projects = [...byProject.values()];
const summary = {
  totalProjects: projects.length,
  blocked: projects.filter((p) => p.status === 'bloqueado').length,
  atRisk: projects.filter((p) => p.status === 'en_riesgo').length,
  decisionsNeeded: projects.filter((p) => p.blocker).map((p) => ({ project: p.name, owner: p.owner, request: p.blocker })),
  nextEvents: data.events.slice().sort((a, b) => a.start.localeCompare(b.start)).slice(0, 3)
};
return [{ json: { generatedAt: data.capturedAt, summary, projects } }];
